"use client";

/**
 * Transcript Viewer
 * @registryCategory display
 */

import {
  createContext,
  useContext,
  useMemo,
  type ComponentPropsWithoutRef,
  type ComponentPropsWithRef,
  type HTMLAttributes,
  type ReactNode,
} from "react";

import { Button } from "@/components/ui/static/button";
import {
  ScrubBarContainer,
  ScrubBarProgress,
  ScrubBarThumb,
  ScrubBarTimeLabel,
  ScrubBarTrack,
} from "@/components/ui/audio/scrub-bar";
import {
  useTranscriptViewer,
  type CharacterAlignmentResponseModel,
  type TranscriptGap,
  type TranscriptSegment,
  type TranscriptWord as TranscriptWordType,
  type UseTranscriptViewerProps,
  type UseTranscriptViewerResult,
} from "@/hooks/use-transcript-viewer";
import { cn } from "@/lib/utils";

// ---- ICONS -----------------------------------------------------------------

function PlayIcon({ className, ...props }: ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="currentColor"
      aria-hidden="true"
      className={className}
      {...props}
    >
      <path d="M8 5.14v14l11-7-11-7z" />
    </svg>
  );
}

function PauseIcon({ className, ...props }: ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="currentColor"
      aria-hidden="true"
      className={className}
      {...props}
    >
      <path d="M6 4h4v16H6V4Zm8 0h4v16h-4V4Z" />
    </svg>
  );
}

// ---- CONTEXT ----------------------------------------------------------------

type TranscriptViewerContextValue = UseTranscriptViewerResult & {
  alignment?: CharacterAlignmentResponseModel;
  audioProps: ComponentPropsWithRef<"audio">;
};

const TranscriptViewerContext =
  createContext<TranscriptViewerContextValue | null>(null);

function useTranscriptViewerContext() {
  const context = useContext(TranscriptViewerContext);
  if (!context) {
    throw new Error(
      "useTranscriptViewerContext must be used within a TranscriptViewer"
    );
  }
  return context;
}

type TranscriptViewerProviderProps = {
  value: TranscriptViewerContextValue;
  children: ReactNode;
};

function TranscriptViewerProvider({
  value,
  children,
}: TranscriptViewerProviderProps) {
  return (
    <TranscriptViewerContext.Provider value={value}>
      {children}
    </TranscriptViewerContext.Provider>
  );
}

// ---- CONTAINER --------------------------------------------------------------

type AudioMimeType =
  | "audio/mpeg"
  | "audio/wav"
  | "audio/ogg"
  | "audio/mp3"
  | "audio/m4a"
  | "audio/aac"
  | "audio/webm";

export type TranscriptViewerContainerProps = {
  audioSrc?: string;
  src?: string;
  audioType?: AudioMimeType;
  alignment?: CharacterAlignmentResponseModel;
  text?: string;
  segmentComposer?: UseTranscriptViewerProps["segmentComposer"];
  composer?: UseTranscriptViewerProps["composer"];
  hideAudioTags?: boolean;
  children?: ReactNode;
} & Omit<ComponentPropsWithoutRef<"div">, "children"> &
  Pick<
    UseTranscriptViewerProps,
    "onPlay" | "onPause" | "onTimeUpdate" | "onEnded" | "onDurationChange"
  >;

function TranscriptViewerContainer({
  audioSrc,
  src,
  audioType = "audio/mpeg",
  alignment,
  text,
  segmentComposer,
  composer,
  hideAudioTags = true,
  children,
  className,
  onPlay,
  onPause,
  onTimeUpdate,
  onEnded,
  onDurationChange,
  ...props
}: TranscriptViewerContainerProps) {
  const viewerState = useTranscriptViewer({
    alignment,
    text,
    segmentComposer,
    composer,
    hideAudioTags,
    onPlay,
    onPause,
    onTimeUpdate,
    onEnded,
    onDurationChange,
  });

  const { audioRef } = viewerState;
  const resolvedAudioSrc = audioSrc ?? src;

  const audioProps = useMemo(
    () => ({
      ref: audioRef,
      controls: false,
      preload: "metadata" as const,
      src: resolvedAudioSrc,
      children: resolvedAudioSrc ? (
        <source src={resolvedAudioSrc} type={audioType} />
      ) : undefined,
    }),
    [audioRef, resolvedAudioSrc, audioType]
  );

  const contextValue = useMemo(
    () => ({
      ...viewerState,
      alignment,
      audioProps,
    }),
    [viewerState, alignment, audioProps]
  );

  return (
    <TranscriptViewerProvider value={contextValue}>
      <div
        data-slot="transcript-viewer-root"
        className={cn("space-y-4 p-4", className)}
        {...props}
      >
        {children}
      </div>
    </TranscriptViewerProvider>
  );
}

// ---- WORDS ------------------------------------------------------------------

type TranscriptViewerWordStatus = "spoken" | "unspoken" | "current";

interface TranscriptViewerWordProps extends Omit<
  HTMLAttributes<HTMLSpanElement>,
  "children"
> {
  word: TranscriptWordType;
  status: TranscriptViewerWordStatus;
  children?: ReactNode;
}

function TranscriptViewerWord({
  word,
  status,
  className,
  children,
  ...props
}: TranscriptViewerWordProps) {
  return (
    <span
      data-slot="transcript-word"
      data-kind="word"
      data-status={status}
      className={cn(
        "rounded-sm px-0.5 transition-colors",
        status === "spoken" && "text-foreground",
        status === "unspoken" && "text-muted-foreground",
        status === "current" && "bg-primary text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ?? word.text}
    </span>
  );
}

interface TranscriptViewerWordsProps extends HTMLAttributes<HTMLDivElement> {
  renderWord?: (props: {
    word: TranscriptWordType;
    status: TranscriptViewerWordStatus;
  }) => ReactNode;
  renderGap?: (props: {
    segment: TranscriptGap;
    status: TranscriptViewerWordStatus;
  }) => ReactNode;
  wordClassNames?: string;
  gapClassNames?: string;
}

function TranscriptViewerWords({
  className,
  renderWord,
  renderGap,
  wordClassNames,
  gapClassNames,
  ...props
}: TranscriptViewerWordsProps) {
  const {
    spokenSegments,
    unspokenSegments,
    currentWord,
    segments,
    duration,
    currentTime,
    seekToWord,
  } = useTranscriptViewerContext();

  const nearEnd = useMemo(() => {
    if (!duration) {
      return false;
    }

    return currentTime >= duration - 0.01;
  }, [currentTime, duration]);

  const segmentsWithStatus = useMemo(() => {
    if (nearEnd) {
      return segments.map((segment) => ({
        segment,
        status: "spoken" as const,
      }));
    }

    const entries: Array<{
      segment: TranscriptSegment;
      status: TranscriptViewerWordStatus;
    }> = [];

    for (const segment of spokenSegments) {
      entries.push({ segment, status: "spoken" });
    }

    if (currentWord) {
      entries.push({ segment: currentWord, status: "current" });
    }

    for (const segment of unspokenSegments) {
      entries.push({ segment, status: "unspoken" });
    }

    return entries;
  }, [spokenSegments, unspokenSegments, currentWord, nearEnd, segments]);

  return (
    <div
      data-slot="transcript-words"
      className={cn("text-xl leading-relaxed", className)}
      {...props}
    >
      {segmentsWithStatus.map(({ segment, status }) => {
        if (segment.kind === "gap") {
          const content = renderGap
            ? renderGap({ segment, status })
            : segment.text;

          return (
            <span
              key={`gap-${segment.segmentIndex}`}
              data-kind="gap"
              data-status={status}
              className={cn(gapClassNames)}
            >
              {content}
            </span>
          );
        }

        if (renderWord) {
          return (
            <span
              key={`word-${segment.segmentIndex}`}
              data-kind="word"
              data-status={status}
              className={cn(wordClassNames)}
            >
              {renderWord({ word: segment, status })}
            </span>
          );
        }

        return (
          <TranscriptViewerWord
            key={`word-${segment.segmentIndex}`}
            word={segment}
            status={status}
            className={cn(wordClassNames, "cursor-pointer")}
            onClick={() => seekToWord(segment)}
          />
        );
      })}
    </div>
  );
}

// ---- AUDIO ------------------------------------------------------------------

function TranscriptViewerAudio({
  ...props
}: ComponentPropsWithoutRef<"audio">) {
  const { audioProps } = useTranscriptViewerContext();

  if (!audioProps.src) {
    return null;
  }

  return (
    <audio
      data-slot="transcript-audio"
      {...audioProps}
      {...props}
      ref={audioProps.ref}
    />
  );
}

// ---- PLAY / PAUSE -----------------------------------------------------------

type RenderChildren = (state: { isPlaying: boolean }) => ReactNode;

type TranscriptViewerPlayPauseButtonProps = Omit<
  ComponentPropsWithoutRef<typeof Button>,
  "children"
> & {
  children?: ReactNode | RenderChildren;
};

function TranscriptViewerPlayPauseButton({
  className,
  children,
  onClick,
  ...props
}: TranscriptViewerPlayPauseButtonProps) {
  const { isPlaying, play, pause } = useTranscriptViewerContext();
  const Icon = isPlaying ? PauseIcon : PlayIcon;

  const handleClick = (event: React.MouseEvent<HTMLButtonElement>) => {
    if (isPlaying) {
      pause();
    } else {
      play();
    }

    onClick?.(event);
  };

  const content =
    typeof children === "function"
      ? (children as RenderChildren)({ isPlaying })
      : children;

  return (
    <Button
      data-slot="transcript-play-pause-button"
      type="button"
      variant="outline"
      size="icon"
      aria-label={isPlaying ? "Pause audio" : "Play audio"}
      data-playing={isPlaying}
      className={cn("cursor-pointer", className)}
      onClick={handleClick}
      {...props}
    >
      {content ?? <Icon className="size-4" />}
    </Button>
  );
}

// ---- SCRUB BAR --------------------------------------------------------------

type TranscriptViewerScrubBarProps = Omit<
  ComponentPropsWithoutRef<typeof ScrubBarContainer>,
  "duration" | "value" | "onScrub" | "onScrubStart" | "onScrubEnd"
> & {
  showTime?: boolean;
  showTimeLabels?: boolean;
  labelsClassName?: string;
  trackClassName?: string;
  progressClassName?: string;
  thumbClassName?: string;
};

function TranscriptViewerScrubBar({
  className,
  showTime,
  showTimeLabels,
  labelsClassName,
  trackClassName,
  progressClassName,
  thumbClassName,
  ...props
}: TranscriptViewerScrubBarProps) {
  const { duration, currentTime, seekToTime, startScrubbing, endScrubbing } =
    useTranscriptViewerContext();

  const shouldShowTimeLabels = showTimeLabels ?? showTime ?? true;

  return (
    <ScrubBarContainer
      data-slot="transcript-scrub-bar"
      duration={duration}
      value={currentTime}
      onScrubStart={startScrubbing}
      onScrubEnd={endScrubbing}
      onScrub={seekToTime}
      className={className}
      {...props}
    >
      <div className="flex flex-1 flex-col gap-1">
        <ScrubBarTrack className={trackClassName}>
          <ScrubBarProgress className={progressClassName} />
          <ScrubBarThumb className={thumbClassName} />
        </ScrubBarTrack>
        {shouldShowTimeLabels && (
          <div
            className={cn(
              "text-muted-foreground flex items-center justify-between text-xs",
              labelsClassName
            )}
          >
            <ScrubBarTimeLabel time={currentTime} />
            <ScrubBarTimeLabel time={Math.max(0, duration - currentTime)} />
          </div>
        )}
      </div>
    </ScrubBarContainer>
  );
}

// ---- EXPORTS ----------------------------------------------------------------

export {
  TranscriptViewerAudio,
  TranscriptViewerContainer,
  TranscriptViewerPlayPauseButton,
  TranscriptViewerProvider,
  TranscriptViewerScrubBar,
  TranscriptViewerWord,
  TranscriptViewerWords,
  useTranscriptViewerContext,
};
export type { CharacterAlignmentResponseModel };

"use client";

/**
 * useTranscriptViewer
 * @registryDescription Hook for transcript playback, word timing, scrubbing, and current-word tracking.
 * @registryVariant audio
 */

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
  type RefObject,
} from "react";

// ---- TYPES -----------------------------------------------------------------

type AlignmentPayload = {
  characters?: string[];
  characterStartTimesSeconds?: number[];
  characterEndTimesSeconds?: number[];
  character_start_times_seconds?: number[];
  character_end_times_seconds?: number[];
};

type AlignmentCharacter = {
  character: string;
  startTimeMs: number;
  endTimeMs: number;
};

/** Supports both the repo's nested alignment shape and the upstream top-level shape. */
export interface CharacterAlignmentResponseModel extends AlignmentPayload {
  alignment?: AlignmentPayload;
  normalized_alignment?: AlignmentPayload;
  normalizedAlignment?: AlignmentPayload;
}

export type ComposeSegmentsOptions = {
  hideAudioTags?: boolean;
};

type BaseSegment = {
  segmentIndex: number;
  text: string;
};

export type TranscriptWord = BaseSegment & {
  kind: "word";
  wordIndex: number;
  startTime: number;
  endTime: number;
};

export type TranscriptGap = BaseSegment & {
  kind: "gap";
};

export type TranscriptSegment = TranscriptWord | TranscriptGap;

export type ComposeSegmentsResult = {
  segments: TranscriptSegment[];
  words: TranscriptWord[];
};

export type SegmentComposer = (
  alignment: CharacterAlignmentResponseModel
) => ComposeSegmentsResult;

type CharacterComposer = (
  alignment: CharacterAlignmentResponseModel
) => AlignmentCharacter[];

// ---- HELPERS ---------------------------------------------------------------

function getAlignmentSource(
  alignment: CharacterAlignmentResponseModel | undefined
): AlignmentPayload | undefined {
  return (
    alignment?.normalizedAlignment ??
    alignment?.normalized_alignment ??
    alignment?.alignment ??
    alignment
  );
}

function toAlignmentCharacters(
  alignment: CharacterAlignmentResponseModel,
  composer?: CharacterComposer
): AlignmentCharacter[] {
  if (composer) {
    return composer(alignment);
  }

  const source = getAlignmentSource(alignment);
  const characters = source?.characters ?? [];
  const starts =
    source?.characterStartTimesSeconds ??
    source?.character_start_times_seconds ??
    [];
  const ends =
    source?.characterEndTimesSeconds ??
    source?.character_end_times_seconds ??
    [];

  return characters.map((character, index) => ({
    character,
    startTimeMs: (starts[index] ?? 0) * 1000,
    endTimeMs: (ends[index] ?? starts[index] ?? 0) * 1000,
  }));
}

function composeTextSegments(text: string): ComposeSegmentsResult {
  const segments: TranscriptSegment[] = [];
  const words: TranscriptWord[] = [];
  const tokens = text.match(/\S+|\s+/g) ?? [];

  let segmentIndex = 0;
  let wordIndex = 0;

  for (const token of tokens) {
    if (/\s+/.test(token)) {
      segments.push({
        kind: "gap",
        segmentIndex: segmentIndex++,
        text: token,
      });
      continue;
    }

    const word: TranscriptWord = {
      kind: "word",
      segmentIndex: segmentIndex++,
      wordIndex: wordIndex++,
      text: token,
      startTime: 0,
      endTime: 0,
    };

    segments.push(word);
    words.push(word);
  }

  return { segments, words };
}

// ---- SEGMENT COMPOSITION ---------------------------------------------------

export function composeSegments(
  alignment: CharacterAlignmentResponseModel,
  options: ComposeSegmentsOptions & { composer?: CharacterComposer } = {}
): ComposeSegmentsResult {
  const characters = toAlignmentCharacters(alignment, options.composer);

  if (characters.length === 0) {
    return { segments: [], words: [] };
  }

  const segments: TranscriptSegment[] = [];
  const words: TranscriptWord[] = [];

  let wordBuffer = "";
  let whitespaceBuffer = "";
  let wordStart = 0;
  let wordEnd = 0;
  let segmentIndex = 0;
  let wordIndex = 0;
  let insideAudioTag = false;

  const hideAudioTags = options.hideAudioTags ?? false;

  const flushWhitespace = () => {
    if (!whitespaceBuffer) {
      return;
    }

    segments.push({
      kind: "gap",
      segmentIndex: segmentIndex++,
      text: whitespaceBuffer,
    });
    whitespaceBuffer = "";
  };

  const flushWord = () => {
    if (!wordBuffer) {
      return;
    }

    const word: TranscriptWord = {
      kind: "word",
      segmentIndex: segmentIndex++,
      wordIndex: wordIndex++,
      text: wordBuffer,
      startTime: wordStart / 1000,
      endTime: wordEnd / 1000,
    };

    segments.push(word);
    words.push(word);
    wordBuffer = "";
  };

  for (const character of characters) {
    if (hideAudioTags) {
      if (character.character === "[") {
        flushWord();
        whitespaceBuffer = "";
        insideAudioTag = true;
        continue;
      }

      if (insideAudioTag) {
        if (character.character === "]") {
          insideAudioTag = false;
        }
        continue;
      }
    }

    if (/\s/.test(character.character)) {
      flushWord();
      whitespaceBuffer += character.character;
      continue;
    }

    if (whitespaceBuffer) {
      flushWhitespace();
    }

    if (!wordBuffer) {
      wordBuffer = character.character;
      wordStart = character.startTimeMs;
      wordEnd = character.endTimeMs;
      continue;
    }

    wordBuffer += character.character;
    wordEnd = character.endTimeMs;
  }

  flushWord();
  flushWhitespace();

  return { segments, words };
}

// ---- HOOK ------------------------------------------------------------------

export interface UseTranscriptViewerProps {
  alignment?: CharacterAlignmentResponseModel;
  text?: string;
  segmentComposer?: SegmentComposer;
  composer?: CharacterComposer;
  hideAudioTags?: boolean;
  onPlay?: () => void;
  onPause?: () => void;
  onTimeUpdate?: (time: number) => void;
  onEnded?: () => void;
  onDurationChange?: (duration: number) => void;
}

export interface UseTranscriptViewerResult {
  segments: TranscriptSegment[];
  words: TranscriptWord[];
  spokenSegments: TranscriptSegment[];
  unspokenSegments: TranscriptSegment[];
  currentWord: TranscriptWord | null;
  currentSegmentIndex: number;
  currentWordIndex: number;
  seekToTime: (time: number) => void;
  seekToWord: (word: number | TranscriptWord) => void;
  audioRef: RefObject<HTMLAudioElement | null>;
  isPlaying: boolean;
  isScrubbing: boolean;
  duration: number;
  currentTime: number;
  play: () => void;
  pause: () => void;
  startScrubbing: () => void;
  endScrubbing: (time?: number) => void;
}

export function useTranscriptViewer({
  alignment,
  text,
  segmentComposer,
  composer,
  hideAudioTags = true,
  onPlay,
  onPause,
  onTimeUpdate,
  onEnded,
  onDurationChange,
}: UseTranscriptViewerProps): UseTranscriptViewerResult {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const rafRef = useRef<number | null>(null);
  const handleTimeUpdateRef = useRef<(time: number) => void>(() => {});
  const onDurationChangeRef = useRef<(duration: number) => void>(() => {});

  const [isPlaying, setIsPlaying] = useState(false);
  const [isScrubbing, setIsScrubbing] = useState(false);
  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);

  const { segments, words } = useMemo(() => {
    if (alignment && segmentComposer) {
      return segmentComposer(alignment);
    }

    if (alignment) {
      return composeSegments(alignment, { hideAudioTags, composer });
    }

    if (text) {
      return composeTextSegments(text);
    }

    return { segments: [], words: [] };
  }, [alignment, segmentComposer, hideAudioTags, composer, text]);

  const guessedDuration = useMemo(() => {
    const source = getAlignmentSource(alignment);
    const ends =
      source?.characterEndTimesSeconds ?? source?.character_end_times_seconds;

    if (Array.isArray(ends) && ends.length > 0) {
      const last = ends[ends.length - 1];
      return Number.isFinite(last) ? last : 0;
    }

    if (words.length > 0) {
      const lastWord = words[words.length - 1];
      return Number.isFinite(lastWord.endTime) ? lastWord.endTime : 0;
    }

    return 0;
  }, [alignment, words]);

  const [currentWordIndex, setCurrentWordIndex] = useState<number>(() =>
    words.length > 0 ? 0 : -1
  );

  const findWordIndex = useCallback(
    (time: number) => {
      if (words.length === 0) {
        return -1;
      }

      let low = 0;
      let high = words.length - 1;
      let answer = -1;

      while (low <= high) {
        const middle = Math.floor((low + high) / 2);
        const word = words[middle];

        if (time >= word.startTime && time < word.endTime) {
          answer = middle;
          break;
        }

        if (time < word.startTime) {
          high = middle - 1;
        } else {
          low = middle + 1;
        }
      }

      return answer;
    },
    [words]
  );

  const handleWordTracking = useCallback(
    (nextTime: number) => {
      if (words.length === 0) {
        setCurrentWordIndex(-1);
        return;
      }

      const activeWord =
        currentWordIndex >= 0 && currentWordIndex < words.length
          ? words[currentWordIndex]
          : undefined;

      if (!activeWord) {
        const found = findWordIndex(nextTime);
        if (found !== -1) {
          setCurrentWordIndex(found);
        }
        return;
      }

      let nextIndex = currentWordIndex;

      if (
        nextTime >= activeWord.endTime &&
        currentWordIndex + 1 < words.length
      ) {
        while (
          nextIndex + 1 < words.length &&
          nextTime >= words[nextIndex + 1].startTime
        ) {
          nextIndex += 1;
        }

        if (nextTime < words[nextIndex].endTime) {
          setCurrentWordIndex(nextIndex);
          return;
        }

        setCurrentWordIndex(nextIndex);
        return;
      }

      if (nextTime < activeWord.startTime) {
        const found = findWordIndex(nextTime);
        if (found !== -1) {
          setCurrentWordIndex(found);
        }
        return;
      }

      const found = findWordIndex(nextTime);
      if (found !== -1 && found !== currentWordIndex) {
        setCurrentWordIndex(found);
      }
    },
    [currentWordIndex, findWordIndex, words]
  );

  useEffect(() => {
    handleTimeUpdateRef.current = (time) => {
      handleWordTracking(time);
      onTimeUpdate?.(time);
    };
  }, [handleWordTracking, onTimeUpdate]);

  useEffect(() => {
    onDurationChangeRef.current = onDurationChange ?? (() => {});
  }, [onDurationChange]);

  useEffect(() => {
    setCurrentTime(0);
    setDuration(guessedDuration);
    setIsPlaying(false);
    setIsScrubbing(false);
    setCurrentWordIndex(words.length > 0 ? 0 : -1);
  }, [alignment, text, guessedDuration, words.length]);

  const stopRaf = useCallback(() => {
    if (rafRef.current !== null) {
      cancelAnimationFrame(rafRef.current);
      rafRef.current = null;
    }
  }, []);

  const startRaf = useCallback(() => {
    if (rafRef.current !== null) {
      return;
    }

    const tick = () => {
      const node = audioRef.current;
      if (!node) {
        rafRef.current = null;
        return;
      }

      const nextTime = node.currentTime;
      setCurrentTime(nextTime);
      handleTimeUpdateRef.current(nextTime);

      if (Number.isFinite(node.duration) && node.duration > 0) {
        setDuration((previousDuration) => {
          if (!previousDuration) {
            onDurationChangeRef.current(node.duration);
            return node.duration;
          }
          return previousDuration;
        });
      }

      if (node.paused) {
        rafRef.current = null;
        return;
      }

      rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
  }, []);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) {
      return;
    }

    const syncPlayback = () => {
      setIsPlaying(!audio.paused);
    };

    const syncTime = () => {
      setCurrentTime(audio.currentTime);
    };

    const syncDuration = () => {
      setDuration(Number.isFinite(audio.duration) ? audio.duration : 0);
    };

    const handlePlay = () => {
      syncPlayback();
      startRaf();
      onPlay?.();
    };

    const handlePause = () => {
      syncPlayback();
      syncTime();
      stopRaf();
      onPause?.();
    };

    const handleEnded = () => {
      syncPlayback();
      syncTime();
      stopRaf();
      onEnded?.();
    };

    const handleTimeUpdateEvent = () => {
      syncTime();
      handleTimeUpdateRef.current(audio.currentTime);
    };

    const handleSeeked = () => {
      syncTime();
      handleTimeUpdateRef.current(audio.currentTime);
    };

    const handleDuration = () => {
      syncDuration();
      onDurationChange?.(audio.duration);
    };

    syncPlayback();
    syncTime();
    syncDuration();

    if (!audio.paused) {
      startRaf();
    } else {
      stopRaf();
    }

    audio.addEventListener("play", handlePlay);
    audio.addEventListener("pause", handlePause);
    audio.addEventListener("ended", handleEnded);
    audio.addEventListener("timeupdate", handleTimeUpdateEvent);
    audio.addEventListener("seeked", handleSeeked);
    audio.addEventListener("durationchange", handleDuration);
    audio.addEventListener("loadedmetadata", handleDuration);

    return () => {
      stopRaf();
      audio.removeEventListener("play", handlePlay);
      audio.removeEventListener("pause", handlePause);
      audio.removeEventListener("ended", handleEnded);
      audio.removeEventListener("timeupdate", handleTimeUpdateEvent);
      audio.removeEventListener("seeked", handleSeeked);
      audio.removeEventListener("durationchange", handleDuration);
      audio.removeEventListener("loadedmetadata", handleDuration);
    };
  }, [onDurationChange, onEnded, onPause, onPlay, startRaf, stopRaf]);

  const seekToTime = useCallback((time: number) => {
    const node = audioRef.current;
    if (!node) {
      return;
    }

    setCurrentTime(time);
    node.currentTime = time;
    handleTimeUpdateRef.current(time);
  }, []);

  const seekToWord = useCallback(
    (word: number | TranscriptWord) => {
      const target = typeof word === "number" ? words[word] : word;
      if (!target) {
        return;
      }

      seekToTime(target.startTime);
    },
    [seekToTime, words]
  );

  const play = useCallback(() => {
    const audio = audioRef.current;
    if (!audio) {
      return;
    }

    if (audio.paused) {
      void audio.play();
    }
  }, []);

  const pause = useCallback(() => {
    const audio = audioRef.current;
    if (audio && !audio.paused) {
      audio.pause();
    }
  }, []);

  const startScrubbing = useCallback(() => {
    setIsScrubbing(true);
    stopRaf();
  }, [stopRaf]);

  const endScrubbing = useCallback(
    (time?: number) => {
      if (typeof time === "number") {
        seekToTime(time);
      }

      setIsScrubbing(false);

      const node = audioRef.current;
      if (node && !node.paused) {
        startRaf();
      }
    },
    [seekToTime, startRaf]
  );

  const currentWord =
    currentWordIndex >= 0 && currentWordIndex < words.length
      ? words[currentWordIndex]
      : null;

  const currentSegmentIndex = currentWord?.segmentIndex ?? -1;

  const spokenSegments = useMemo(() => {
    if (segments.length === 0 || currentSegmentIndex <= 0) {
      return [];
    }

    return segments.slice(0, currentSegmentIndex);
  }, [segments, currentSegmentIndex]);

  const unspokenSegments = useMemo(() => {
    if (segments.length === 0) {
      return [];
    }

    if (currentSegmentIndex === -1) {
      return segments;
    }

    if (currentSegmentIndex + 1 >= segments.length) {
      return [];
    }

    return segments.slice(currentSegmentIndex + 1);
  }, [segments, currentSegmentIndex]);

  return {
    segments,
    words,
    spokenSegments,
    unspokenSegments,
    currentWord,
    currentSegmentIndex,
    currentWordIndex,
    seekToTime,
    seekToWord,
    audioRef,
    isPlaying,
    isScrubbing,
    duration: duration || guessedDuration,
    currentTime,
    play,
    pause,
    startScrubbing,
    endScrubbing,
  };
}
